#!/usr/bin/env node

/**
 * AI-Powered Smart Agent with LLM Validation
 * 
 * This is a SMART AGENT that:
 * 1. Registers itself by solving challenges from other smart agents
 * 2. Receives an API key generated by 3 validator smart agents
 * 3. Then acts as a validator using LLM to generate dynamic challenges
 * 
 * Usage:
 *   node ai-validator-agent.js \
 *     --name SmartAI \
 *     --openai-url https://api.openai.com/v1 \
 *     --model gpt-4 \
 *     --api-key sk-...
 */

import Gun from 'gun';
import 'gun/sea.js';
import 'gun/lib/radix.js';
import 'gun/lib/radisk.js';
import 'gun/lib/store.js';
import 'gun/lib/rindexed.js';
import { RegistrationManager } from './registration-manager.js';

// LLM Client for generating challenges
class LLMClient {
    constructor(apiUrl, apiKey, model = 'gpt-4') {
        this.apiUrl = apiUrl || 'https://api.openai.com/v1';
        this.apiKey = apiKey;
        this.model = model;
    }

    async generateChallenge(difficulty = 'medium') {
        const prompt = `Generate a unique proof-of-intelligence challenge for an AI agent registration system.

Requirements:
- Difficulty: ${difficulty}
- Question must be solvable by an intelligent agent
- Include a clear, unambiguous answer (one word or short phrase)
- Challenge types: math, logic, pattern recognition, word puzzles, or code comprehension

Return ONLY valid JSON with this structure:
{
  "question": "your challenge question",
  "answer": "correct answer",
  "type": "math|logic|pattern|code|word",
  "difficulty": "${difficulty}"
}

Be creative and avoid common questions. The question should test intelligence, not memorization.`;

        try {
            const response = await fetch(`${this.apiUrl}/chat/completions`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.apiKey}`
                },
                body: JSON.stringify({
                    model: this.model,
                    messages: [
                        {
                            role: 'system',
                            content: 'You are a challenge generator for an AI agent network. Generate creative, fair, and solvable puzzles.'
                        },
                        {
                            role: 'user',
                            content: prompt
                        }
                    ],
                    temperature: 0.9, // High creativity
                    max_tokens: 300
                })
            });

            if (!response.ok) {
                const errorText = await response.text();
                console.error(`   API Response Status: ${response.status}`);
                console.error(`   API Response Body: ${errorText}`);
                throw new Error(`LLM API error: ${response.statusText}`);
            }

            const data = await response.json();
            const content = data.choices[0].message.content.trim();
            
            // Clean up markdown code blocks if present
            const jsonStr = content
                .replace(/```json\n?/g, '')
                .replace(/```\n?/g, '')
                .trim();
            
            return JSON.parse(jsonStr);
        } catch (error) {
            console.error('❌ Failed to generate challenge:', error.message);
            
            // Fallback to hardcoded challenge
            return {
                question: 'What is 7 + 8?',
                answer: '15',
                type: 'math',
                difficulty: 'easy'
            };
        }
    }

    async solveChallenge(question, type) {
        const prompt = `Solve this challenge:

Type: ${type}
Question: ${question}

Provide ONLY the answer - no explanation, no extra text. Just the answer.`;

        try {
            const response = await fetch(`${this.apiUrl}/chat/completions`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.apiKey}`
                },
                body: JSON.stringify({
                    model: this.model,
                    messages: [
                        {
                            role: 'system',
                            content: 'You solve puzzles and challenges. Provide only the answer, no explanation.'
                        },
                        {
                            role: 'user',
                            content: prompt
                        }
                    ],
                    temperature: 0.3, // Low temperature for accuracy
                    max_tokens: 50
                })
            });

            if (!response.ok) {
                throw new Error(`LLM API error: ${response.statusText}`);
            }

            const data = await response.json();
            return data.choices[0].message.content.trim();
        } catch (error) {
            console.error('❌ Failed to solve challenge:', error.message);
            return null;
        }
    }

    async testConnection() {
        try {
            const response = await fetch(`${this.apiUrl}/models`, {
                headers: {
                    'Authorization': `Bearer ${this.apiKey}`
                }
            });
            return response.ok;
        } catch (error) {
            return false;
        }
    }
}

// AI-Powered Challenge Generator (replaces hardcoded PeerChallenge)
class AIPeerChallenge {
    constructor(llmClient) {
        this.llm = llmClient;
    }

    async generate() {
        const challenge = await this.llm.generateChallenge('medium');
        return {
            type: challenge.type,
            question: challenge.question,
            answer: challenge.answer
        };
    }

    async solve(challenge) {
        // Use LLM to solve the challenge
        return await this.llm.solveChallenge(challenge.question, challenge.type);
    }

    async verify(challenge, solution) {
        const normalized = (str) => String(str || '').toLowerCase().trim();
        return normalized(solution) === normalized(challenge.answer);
    }
}

// Smart AI Agent (Registers itself, then validates others)
class SmartAIAgent {
    constructor(name, llmClient, relayUrl) {
        this.name = name;
        this.llm = llmClient;
        this.relayUrl = relayUrl;
        this.keypair = null;
        this.gun = null;
        this.db = null;
        this.apiKey = null;
        this.aiChallenge = null;
    }

    async initialize() {
        console.log(`\n🤖 Smart AI Agent: ${this.name}`);
        console.log(`🔗 Relay: ${this.relayUrl}`);
        
        // Generate keypair
        this.keypair = await Gun.SEA.pair();
        console.log(`🔑 Public Key: ${this.keypair.pub.substring(0, 20)}...`);

        // Create AI challenge generator
        this.aiChallenge = new AIPeerChallenge(this.llm);

        // Check for master validator key first (highest priority)
        const masterKey = process.env.VALIDATOR_MASTER_KEY || process.env.RELAY_API_KEY;
        if (masterKey) {
            console.log(`✅ Using validator master key (${masterKey.substring(0, 8)}...${masterKey.substring(masterKey.length - 4)})`);
            this.apiKey = masterKey;
        } else {
            // Check if already registered
            const regManager = new RegistrationManager(this.name, this.keypair, this.relayUrl);
            
            if (regManager.hasStoredKey()) {
                console.log(`✅ Found existing API key`);
                this.apiKey = regManager.loadStoredKey();
            } else {
                console.log(`\n🔐 No API key found - Starting registration as SMART AGENT...`);
                console.log(`📝 Will solve challenges from other smart agents\n`);
                
                // Initialize Gun with demo key for registration
                this.gun = Gun({
                    peers: [`${this.relayUrl}/gun?key=demo-registration`],
                    radisk: false
                });
                this.db = this.gun.get('agentworkbook-v1');

                // Register using AI challenge solver
                try {
                    this.apiKey = await regManager.register(this.gun, this.db, this.aiChallenge);
                    console.log(`\n✅ Registration complete! API key: ${this.apiKey.substring(0, 20)}...`);
                } catch (error) {
                    console.error(`❌ Registration failed:`, error.message);
                    process.exit(1);
                }
            }
        }

        // Now connect with real API key
        this.gun = Gun({
            peers: [`${this.relayUrl}/gun?key=${this.apiKey}`],
            radisk: true,
            file: `radata-${this.name}`
        });
        this.db = this.gun.get('agentworkbook-v1');

        console.log(`✅ Smart agent initialized with API key\n`);
    }

    async start() {
        console.log(`👁️  Now acting as AI validator for new registrations...\n`);

        // Use existing validator pattern but with AI challenges
        RegistrationManager.actAsValidator(
            this.gun,
            this.db,
            this.name,
            this.keypair,
            'auto-detect',
            this.aiChallenge  // Pass AI challenge generator instead of hardcoded
        );

        // Publish heartbeat
        setInterval(() => {
            this.db.get('agents').get(this.name).put({
                name: this.name,
                role: 'smart-validator',
                type: 'ai-powered',
                pub: this.keypair.pub,
                lastSeen: Date.now()
            });
            console.log(`💓 Heartbeat published`);
        }, 60000);

        console.log(`🚀 Smart AI agent running - validates using LLM-generated challenges\n`);
    }
}

// CLI Argument Parsing
function parseArgs() {
    const args = process.argv.slice(2);
    const config = {
        name: 'SmartAI',
        openaiUrl: process.env.OPENAI_API_URL || 'https://api.openai.com/v1',
        model: process.env.OPENAI_MODEL || 'gpt-4',
        apiKey: process.env.OPENAI_API_KEY,
        relayUrl: process.env.RELAY_URL || 'https://vishalmysore-agentworkbookrelayserver.hf.space'
    };

    for (let i = 0; i < args.length; i++) {
        switch (args[i]) {
            case '--name':
                config.name = args[++i];
                break;
            case '--openai-url':
                config.openaiUrl = args[++i];
                break;
            case '--model':
                config.model = args[++i];
                break;
            case '--api-key':
                config.apiKey = args[++i];
                break;
            case '--relay-url':
                config.relayUrl = args[++i];
                break;
            case '--help':
                console.log(`
Smart AI Agent - Self-Registering Validator with LLM

This is a SMART AGENT that:
1. Registers itself by solving challenges from other smart agents
2. Receives API key from 3 validators  
3. Acts as validator using AI-generated challenges

Usage:
  node ai-validator-agent.js [options]

Options:
  --name <name>           Agent name (default: SmartAI)
  --openai-url <url>      OpenAI API URL (default: https://api.openai.com/v1)
  --model <model>         LLM model (default: gpt-4)
  --api-key <key>         OpenAI API key (or env: OPENAI_API_KEY)
  --relay-url <url>       Gun.js relay URL (or env: RELAY_URL)
  --help                  Show this help

Environment Variables:
  OPENAI_API_URL          OpenAI API endpoint
  OPENAI_MODEL            Model name (gpt-4, gpt-3.5-turbo, etc.)
  OPENAI_API_KEY          OpenAI API key
  RELAY_URL               Gun.js relay server URL

Examples:
  # Basic usage with OpenAI
  node ai-validator-agent.js --name SmartAI1 --api-key sk-...

  # NVIDIA Nemotron
  node ai-validator-agent.js \\
    --name NVIDIAAgent \\
    --openai-url https://integrate.api.nvidia.com/v1 \\
    --model nvidia/nemotron-nano-12b-v2-vl \\
    --api-key nvapi-...

  # Ollama (local, free)
  node ai-validator-agent.js \\
    --name LocalAI \\
    --openai-url http://localhost:11434/v1 \\
    --model llama2 \\
    --api-key ollama
`);
                process.exit(0);
        }
    }

    return config;
}

// Main
async function main() {
    console.log('╔══════════════════════════════════════════════╗');
    console.log('║   Smart AI Agent - LLM-Powered Validator    ║');
    console.log('║   Self-Registers + Validates Others         ║');
    console.log('╚══════════════════════════════════════════════╝\n');

    const config = parseArgs();

    // Validate required config
    if (!config.apiKey) {
        console.error('❌ Error: OpenAI API key required');
        console.error('   Provide via --api-key or OPENAI_API_KEY environment variable\n');
        process.exit(1);
    }

    // Initialize LLM client
    console.log('🧪 Testing LLM connection...');
    const llm = new LLMClient(config.openaiUrl, config.apiKey, config.model);
    
    const isConnected = await llm.testConnection();
    if (!isConnected) {
        console.warn('⚠️  Warning: Could not verify LLM connection');
        console.warn('   Will attempt to use anyway...\n');
    } else {
        console.log('✅ LLM connection verified\n');
    }

    // Test challenge generation
    console.log('🎯 Testing challenge generation...');
    const testChallenge = await llm.generateChallenge('easy');
    console.log(`   Question: ${testChallenge.question}`);
    console.log(`   Type: ${testChallenge.type}`);
    console.log(`   (Answer: ${testChallenge.answer})`);
    console.log('✅ Challenge generation working!\n');

    // Initialize smart agent
    const agent = new SmartAIAgent(
        config.name,
        llm,
        config.relayUrl
    );

    await agent.initialize();
    await agent.start();

    // Keep alive
    console.log('═'.repeat(50));
    console.log('\n💡 Press Ctrl+C to stop.\n');
}

// Run
main().catch(error => {
    console.error('💥 Fatal error:', error);
    process.exit(1);
});
